SELECT E.employee_name, S.employee_name AS supervisor_name
FROM employees E
JOIN employees S ON E.supervisor_id = S.employee_id;

SELECT E.employee_name, D.department_name
FROM employees E
JOIN departments D ON E.department_id = D.department_id;

SELECT employee_id, COUNT(*) AS num_awards
FROM employee_awards
GROUP BY employee_id;

SELECT employee_name 
FROM employees 
WHERE hire_date = (SELECT MAX(hire_date) FROM employees);

SELECT UPPER(employee_name) AS employee_name, job_title, 
       CUME_DIST() OVER (ORDER BY years_with_company) AS cumulative_distribution
FROM employees;

SELECT e.employee_name, e.employee_id, e.salary, j.performance_rating
FROM employees e
JOIN job_performance j ON e.employee_id = j.employee_id
WHERE j.performance_rating = (
  SELECT MAX(performance_rating) FROM job_performance
) AND e.salary > (
  SELECT AVG(salary) FROM employees
);
